using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API.
/// Uses constructor injection — IHttpClientFactory and ILogger are resolved by DI
/// and never appear in the tool schema exposed to LLMs.
/// </summary>
[McpServerToolType]
public class PostsApiTools(IHttpClientFactory httpFactory, ILogger<PostsApiTools> logger)
{
    [McpServerTool, Description("Get a single blog post by its numeric ID.")]
    public async Task<string> GetPost(
        [Description("The post ID (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);

        var client = httpFactory.CreateClient("PostsApi");
        var post = await client.GetFromJsonAsync<Post>($"/posts/{id}", cancellationToken);

        return post is null
            ? "Post not found."
            : $"[{post.Id}] {post.Title}\n\n{post.Body}";
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter by user ID (optional)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var client = httpFactory.CreateClient("PostsApi");
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";

        var posts = await client.GetFromJsonAsync<List<Post>>(url, cancellationToken);

        if (posts is null || posts.Count == 0)
            return "No posts found.";

        return string.Join("\n", posts.Select(p => $"[{p.Id}] {p.Title}"));
    }

    [McpServerTool, Description("Create a new blog post.")]
    public async Task<string> CreatePost(
        [Description("Author user ID")] int userId,
        [Description("Post title")] string title,
        [Description("Post body text")] string body,
        CancellationToken cancellationToken = default)
    {
        var client = httpFactory.CreateClient("PostsApi");
        var response = await client.PostAsJsonAsync("/posts",
            new { userId, title, body }, cancellationToken);

        response.EnsureSuccessStatusCode();
        var created = await response.Content.ReadFromJsonAsync<Post>(cancellationToken);

        return $"Created post with ID {created?.Id}.";
    }
}

internal sealed class Post
{
    [JsonPropertyName("userId")]
    public int UserId { get; set; }

    [JsonPropertyName("id")]
    public int Id { get; set; }

    [JsonPropertyName("title")]
    public string Title { get; set; } = "";

    [JsonPropertyName("body")]
    public string Body { get; set; } = "";
}

